using System;
using System.Data.SqlClient;
using Microsoft.AspNetCore.Mvc;
using Microsoft.Azure.WebJobs;
using Microsoft.Azure.WebJobs.Extensions.Http;
using Microsoft.AspNetCore.Http;
using Newtonsoft.Json;

public static class AzureSqlQueryFunction
{
    [FunctionName("AzureSqlQueryFunction")]
    public static IActionResult Run(
        [HttpTrigger(AuthorizationLevel.Function, "get", Route = null)] HttpRequest req,
        ILogger log)
    {
        string connectionString = Environment.GetEnvironmentVariable("SQLConnectionString");
        string query = req.Query["query"];
        string parameters = req.Query["parameters"];

        if (string.IsNullOrEmpty(query))
        {
            return new BadRequestObjectResult("Query parameter is required.");
        }

        using (SqlConnection connection = new SqlConnection(connectionString))
        {
            try
            {
                connection.Open();
                SqlCommand command = new SqlCommand(query, connection);

                if (!string.IsNullOrEmpty(parameters))
                {
                    var paramArray = JsonConvert.DeserializeObject<Dictionary<string, object>>(parameters);
                    foreach (var param in paramArray)
                    {
                        command.Parameters.AddWithValue(param.Key, param.Value);
                    }
                }

                SqlDataReader reader = command.ExecuteReader();
                dynamic result = new List<dynamic>();

                while (reader.Read())
                {
                    dynamic row = new ExpandoObject();
                    for (int i = 0; i < reader.FieldCount; i++)
                    {
                        ((IDictionary<string, object>)row)[reader.GetName(i)] = reader[i];
                    }
                    result.Add(row);
                }

                return new OkObjectResult(result);
            }
            catch (Exception ex)
            {
                log.LogError(ex, "Error executing SQL query.");
                return new InternalServerErrorResult();
            }
        }
    }
}